const ruToEn: Record<string, string> = {
  'й': 'q', 'ц': 'w', 'у': 'e', 'к': 'r', 'е': 't', 'н': 'y', 'г': 'u', 'ш': 'i', 'щ': 'o', 'з': 'p', 'х': '[', 'ъ': ']',
  'ф': 'a', 'ы': 's', 'в': 'd', 'а': 'f', 'п': 'g', 'р': 'h', 'о': 'j', 'л': 'k', 'д': 'l', 'ж': ';', 'э': "'",
  'я': 'z', 'ч': 'x', 'с': 'c', 'м': 'v', 'и': 'b', 'т': 'n', 'ь': 'm', 'б': ',', 'ю': '.', '.': '/'
};

const fixLayout = (str: string) => {
  return str.split('').map(char => {
    const lower = char.toLowerCase();
    if (ruToEn[lower]) {
      const fixed = ruToEn[lower];
      return char === lower ? fixed : fixed.toUpperCase();
    }
    return char;
  }).join('');
};

const ExcelUploader = ({ onUpload, disabled = false }: { onUpload: (data: any[], fileName?: string, sourceFile?: File) => void | Promise<void>; disabled?: boolean }) => {
  return (
    <div className="oc-card p-6">
      <h2 className="text-lg font-bold text-gray-900 mb-4">Загрузка отчета</h2>
      <div className={`border-2 border-dashed rounded-xl p-4 md:p-8 text-center transition-colors ${disabled ? 'border-gray-200 bg-gray-50' : 'border-gray-200 hover:border-indigo-500'}`}>
        <input
          type="file"
          accept=".xlsx, .xls"
          multiple
          disabled={disabled}
          onChange={async (e) => {
            const files = Array.from(e.target.files || []);
            if (!files.length) return;

            const errors: string[] = [];

            try {
              for (let fi = 0; fi < files.length; fi += 1) {
                const file = files[fi];
                if (fi > 0) {
                  await new Promise((r) => setTimeout(r, 350));
                }
                try {
                  const fileSizeError = ensureExcelFileSize(file);
                  if (fileSizeError) {
                    errors.push(`${file.name}: ${fileSizeError}`);
                    continue;
                  }

                  const buff = await file.arrayBuffer();
                  const data = await readFirstSheetAsJson(buff);
                  if (Array.isArray(data)) {
                    const rowLimitError = ensureExcelRowLimit(data.length);
                    if (rowLimitError) {
                      errors.push(`${file.name}: ${rowLimitError}`);
                      continue;
                    }
                  }

                  await onUpload(data, file.name, file);
                } catch (error: any) {
                  errors.push(`${file.name}: ${error?.message || 'неизвестно'}`);
                }
              }

              if (errors.length) {
                alert(`Часть файлов не обработана:\n\n${errors.slice(0, 8).join('\n')}`);
              }
            } finally {
              if (e.target) e.target.value = '';
            }
          }}
          className="hidden"
          id="excel-upload"
        />
        <label htmlFor="excel-upload" className={`flex flex-col items-center ${disabled ? 'cursor-not-allowed opacity-60' : 'cursor-pointer'}`}>
          <div className="p-4 bg-indigo-50 rounded-full mb-4">
            <Upload className="h-8 w-8 text-indigo-600" />
          </div>
          <span className="text-gray-900 font-medium">{disabled ? 'Сначала выберите поставщика' : 'Нажмите для загрузки'}</span>
          <span className="text-sm text-gray-500 mt-1">{disabled ? 'Загрузка недоступна без выбранного поставщика' : 'можно выбрать один или несколько файлов Excel'}</span>
        </label>
      </div>
    </div>
  );
};

