  const normalizeHSCategory = (value: string) => {
    const raw = String(value || '').trim();
    const lowered = raw.toLowerCase();

    if (lowered === 'костюмы' || lowered === 'костюмы спортивные') {
      return 'Костюмы / Костюмы спортивные';
    }

    return raw;
  };

  const fetchSupplierCategories = async (supplierId: string) => {
    setLoadingCategories(true);
    setSupplierCategories([]);

    const supplier = suppliers.find(s => s.id === supplierId);
    if (!supplier || !supplier.wb_api_token) {
      setLoadingCategories(false);
      return;
    }

    const categoriesSet = new Set<string>();

    try {
      let cursor: { updatedAt?: string; nmID?: number; limit: number } = { limit: 100 };
      let page = 0;

      while (page < 40) {
        let response: Response | null = null;

        // retry for temporary WB throttling/errors
        for (let attempt = 0; attempt < 3; attempt++) {
          response = await fetch('https://content-api.wildberries.ru/content/v2/get/cards/list', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': supplier.wb_api_token
            },
            body: JSON.stringify({
              settings: {
                cursor,
                filter: { withPhoto: -1 }
              }
            })
          });

          if (response.ok) break;
          if (response.status !== 429 && response.status < 500) break;
          await new Promise((r) => setTimeout(r, 500 + attempt * 700));
        }

        if (!response || !response.ok) {
          const status = response?.status || 0;
          const errorText = response ? await response.text() : '';
          console.error('WB API Error:', status, errorText);

          // If we already collected something, keep partial result instead of hard fail
          if (categoriesSet.size > 0) break;
          throw new Error(`WB API ${status}`);
        }

        const data = await response.json();
        const cards: any[] = data?.cards || [];

        for (const c of cards) {
          const subject = normalizeHSCategory(String(c?.subjectName || c?.object || '').trim());
          if (subject) categoriesSet.add(subject);
        }

        if (!cards.length) break;

        const nextCursor = data?.cursor || {};
        const nextNmId = nextCursor?.nmID ?? nextCursor?.nmId;
        if (!nextCursor?.updatedAt || !nextNmId) break;

        cursor = {
          limit: 100,
          updatedAt: nextCursor.updatedAt,
          nmID: Number(nextNmId),
        };

        page += 1;
      }

      // Fallback to local HS categories if WB returned nothing
      if (categoriesSet.size === 0) {
        const { data: hsRows } = await supabase
          .from('unified_honest_sign_codes')
          .select('category')
          .eq('supplier_id', supplierId)
          .not('category', 'is', null)
          .limit(5000);

        (hsRows || []).forEach((r: any) => {
          const cat = normalizeHSCategory(String(r?.category || '').trim());
          if (cat) categoriesSet.add(cat);
        });
      }

      const categories = Array.from(categoriesSet).sort((a, b) => a.localeCompare(b, 'ru'));
      setSupplierCategories(categories);

      if (categories.length === 0) {
        showToast('Категории не найдены для выбранного поставщика', 'info');
      }

    } catch (e: any) {
      console.error('Error fetching categories:', e);
      // Fallback even on network/CORS errors
      try {
        const { data: hsRows } = await supabase
          .from('unified_honest_sign_codes')
          .select('category')
          .eq('supplier_id', supplierId)
          .not('category', 'is', null)
          .limit(5000);

        const categoriesSet = new Set<string>();
        (hsRows || []).forEach((r: any) => {
          const cat = normalizeHSCategory(String(r?.category || '').trim());
          if (cat) categoriesSet.add(cat);
        });

        const categories = Array.from(categoriesSet).sort((a, b) => a.localeCompare(b, 'ru'));
        setSupplierCategories(categories);

        if (categories.length > 0) {
          showToast('Категории загружены из локальной базы (WB временно недоступен)', 'info');
        } else {
          showToast(`Ошибка загрузки категорий: ${e?.message || 'неизвестно'}`, 'error');
        }
      } catch {
        showToast(`Ошибка загрузки категорий: ${e?.message || 'неизвестно'}`, 'error');
      }
    } finally {
      setLoadingCategories(false);
    }
  };

  const fetchHonestSignUploadHistory = async () => {
    if (!honestSignSupplierId) return;

    const { data: codes } = await supabase
        .from('unified_honest_sign_codes')
        .select('file_name, created_at, category')
        .eq('supplier_id', honestSignSupplierId)
        .neq('file_name', 'Напечатанные QR')
        .neq('file_name', 'Отсканировано')
        .order('created_at', { ascending: false })
        .limit(5000);

    if (!codes) return;

    const history: any[] = [];
    const seen = new Set();

    for (const code of codes) {
        const key = `${code.file_name}-${new Date(code.created_at).setSeconds(0,0)}`;
        if (!seen.has(key)) {
            seen.add(key);
            history.push({
                file_name: code.file_name,
                created_at: code.created_at,
                category: normalizeHSCategory(code.category)
            });
        }
    }

    setHonestSignUploadHistory(history);
  };

