  const handlePrintHonestSignHistory = async (fileName: string, date: string) => {
    try {
        const targetDate = new Date(date);
        const start = new Date(targetDate.getTime() - 3600000).toISOString();
        const end = new Date(targetDate.getTime() + 3600000).toISOString();

        let { data: codes } = await supabase
            .from('unified_honest_sign_codes')
            .select('code')
            .eq('supplier_id', honestSignSupplierId)
            .eq('file_name', fileName)
            .gte('created_at', start)
            .lte('created_at', end);

        if (!codes || codes.length === 0) {
             const { data: codesFallback } = await supabase
                .from('unified_honest_sign_codes')
                .select('code')
                .eq('supplier_id', honestSignSupplierId)
                .eq('file_name', fileName);

             if (!codesFallback || codesFallback.length === 0) {
                 showToast('Коды не найдены', 'error');
                 return;
             }
             codes = codesFallback;
        }

        showToast('Генерация PDF...', 'success');

        const doc = new jsPDF({
            orientation: 'landscape',
            unit: 'mm',
            format: [58, 40]
        });

        for (let i = 0; i < codes.length; i++) {
            const code = codes[i].code;
            if (i > 0) doc.addPage([58, 40], 'landscape');

            const canvas = document.createElement('canvas');
            try {
                bwipjs.toCanvas(canvas, {
                    bcid: 'datamatrix',
                    text: code,
                    scale: 2,
                    height: 20,
                    includetext: false,
                    textxalign: 'center',
                });

                const imgData = canvas.toDataURL('image/png');
                doc.addImage(imgData, 'PNG', 14, 2, 30, 30);

                doc.setFontSize(7);
                const splitText = doc.splitTextToSize(code, 54);
                doc.text(splitText, 29, 34, { align: 'center' });

            } catch (err) {
                console.error("Error generating barcode", err);
            }
        }

        doc.save(`${fileName || 'codes'}.pdf`);

    } catch (e) {
        console.error(e);
        showToast('Ошибка создания PDF', 'error');
    }
  };

  const handleDownloadHonestSignHistory = async (fileName: string, date: string) => {
    try {
        const targetDate = new Date(date);
        const start = new Date(targetDate.getTime() - 3600000).toISOString();
        const end = new Date(targetDate.getTime() + 3600000).toISOString();

        let { data: codes } = await supabase
            .from('unified_honest_sign_codes')
            .select('code')
            .eq('supplier_id', honestSignSupplierId)
            .eq('file_name', fileName)
            .gte('created_at', start)
            .lte('created_at', end);

        if (!codes || codes.length === 0) {
             const { data: codesFallback } = await supabase
                .from('unified_honest_sign_codes')
                .select('code')
                .eq('supplier_id', honestSignSupplierId)
                .eq('file_name', fileName);

             if (!codesFallback || codesFallback.length === 0) {
                 showToast('Коды не найдены', 'error');
                 return;
             }
             codes = codesFallback;
        }

        const textContent = codes.map(c => c.code).join('\n');
        const blob = new Blob([textContent], { type: 'text/plain;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = fileName.endsWith('.txt') ? fileName : `${fileName}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

    } catch (e) {
        console.error(e);
        showToast('Ошибка скачивания', 'error');
    }
  };

