  const isTimeBasedWorkRate = (rateId: string) => {
    if (String(rateId) === CW_TIME_RATE_KEY) return true;
    const rate = cwWorkRates.find((r: any) => String(r.id) === String(rateId));
    const name = String(rate?.name || '').toLowerCase();
    return name.includes('мин') || name.includes('час') || name.includes('время');
  };

  const ensureCwTimeRateId = async () => {
    const existing = cwWorkRates.find((r: any) => String(r?.name || '').trim().toLowerCase() === CW_TIME_RATE_NAME.toLowerCase());
    if (existing?.id) return String(existing.id);

    const { data, error } = await supabase.from('work_rates').insert([{ name: CW_TIME_RATE_NAME, price: CW_TIME_RATE_PRICE }]).select('id, name, price').single();
    if (error) throw error;
    if (data) setCwWorkRates((prev) => [...prev, data as any]);
    return String((data as any)?.id || '');
  };

  const getCwTimeRate = () => cwWorkRates.find((r: any) => String(r?.name || '').trim().toLowerCase() === CW_TIME_RATE_NAME.toLowerCase());
  const getDatesInRange = (start: string, end: string) => {
    if (!start || !end) return [] as string[];
    const out: string[] = [];
    const cur = new Date(`${start}T00:00:00`);
    const finish = new Date(`${end}T00:00:00`);
    while (cur <= finish) {
      out.push(cur.toISOString().split('T')[0]);
      cur.setDate(cur.getDate() + 1);
    }
    return out;
  };
  const getCwTimeRatePrice = () => Number(getCwTimeRate()?.price ?? CW_TIME_RATE_PRICE);
