  const refreshBarterPhotos = async () => {
    const supplierId = barterSupplierId || selectedSupplierId;
    if (!supplierId) return showToast('Сначала выберите поставщика', 'error');
    try {
      setBarterPhotoLoading(true);
      const next: Record<string, string> = {};
      const norm = (v: any) => String(v ?? '').replace(/\D+/g, '').replace(/^0+/, '');

      const { data: cacheRows, error } = await supabase
        .from('wb_products_cache')
        .select('product_json')
        .eq('supplier_id', supplierId)
        .limit(10000);
      if (error) throw error;

      const byNm: Record<string, string> = {};
      const byVendor: Record<string, string> = {};

      (cacheRows || []).forEach((row: any) => {
        const p = row?.product_json || {};
        const nm = norm(p?.nmID || p?.nm_id || p?.nmId || '');
        const vendorCode = String(p?.vendorCode || p?.supplierArticle || p?.article || '').trim();
        const first = (Array.isArray(p?.photos) && p.photos[0]) || (Array.isArray(p?.mediaFiles) && p.mediaFiles[0]) || '';
        let src = typeof first === 'string' ? first : (first?.big || first?.c246x328 || first?.tm || '');
        src = String(src || '').trim();
        if (src && src.startsWith('//')) src = `https:${src}`;
        if (!/^https?:\/\//i.test(src)) return;
        if (nm) byNm[nm] = src;
        if (vendorCode) byVendor[vendorCode.toLowerCase()] = src;
      });

      (barterCatalogProducts || []).forEach((p: any) => {
        if (String(p?.supplier_id || '') !== String(supplierId)) return;
        const pid = String(p.id || '');
        if (!pid) return;
        const nm = norm(p?.wb_sku || p?.nmID || p?.nmId || '');
        const vendor = String(p?.vendorCode || p?.article || p?.wb_sku || '').toLowerCase().trim();
        const src = (nm && byNm[nm]) || (vendor && byVendor[vendor]) || '';
        if (src) next[pid] = src;
      });

      setBarterPhotoMap((prev) => ({ ...(prev || {}), ...(next || {}) }));
      showToast(`Фото обновлены: ${Object.keys(next).length}`, 'success');
    } catch (e: any) {
      showToast('Ошибка обновления фото: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setBarterPhotoLoading(false);
    }
  };

  const refreshBarterPhotosInCards = async () => {
    const supplierIds = Array.from(new Set((monthRows || []).map((r: any) => String(r?.supplier_id || '')).filter(Boolean)));
    if (!supplierIds.length) return showToast('Нет карточек для обновления фото', 'info');
    try {
      setBarterPhotoLoading(true);
      const { data, error } = await supabase
        .from('wb_products_cache')
        .select('supplier_id, nm_id, product_json')
        .in('supplier_id', supplierIds)
        .limit(10000);
      if (error) throw error;

      const photoByKey: Record<string, string> = {};
      (data || []).forEach((row: any) => {
        const p = row?.product_json || {};
        const nm = String(row?.nm_id || p?.nmID || p?.nmId || '').trim();
        const first = (Array.isArray(p?.photos) && p.photos[0]) || '';
        let src = typeof first === 'string' ? first : (first?.big || first?.tm || first?.c246x328 || '');
        src = String(src || '').trim();
        if (src && src.startsWith('//')) src = `https:${src}`;
        if (!nm || !/^https?:\/\//i.test(src)) return;
        photoByKey[`${String(row?.supplier_id)}__${nm}`] = src;
      });

      let updated = 0;
      setBarterRows((prev) => (prev || []).map((r: any) => {
        if (String(r?.month || '') !== String(barterMonth)) return r;
        const key = `${String(r?.supplier_id || '')}__${String(r?.product_id || '')}`;
        const src = photoByKey[key] || '';
        if (src && src !== r.product_photo) {
          updated += 1;
          return { ...r, product_photo: src };
        }
        return r;
      }));
      showToast(`Фото в карточках обновлены: ${updated}`, 'success');
    } catch (e: any) {
      showToast('Ошибка обновления фото: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setBarterPhotoLoading(false);
    }
  };

  const monthNamesRu = ['янв', 'фев', 'мар', 'апр', 'май', 'июн', 'июл', 'авг', 'сен', 'окт', 'ноя', 'дек'];

