      if (change || assemblyChange) return true; // всегда оставляем откатываемые действия
      const action = String(log?.action || '').toLowerCase();
      const details = String(log?.details || '').toLowerCase();
      return [
        'удал', 'создан', 'измен', 'откат', 'ошиб', 'восстанов', 'закрыт', 'отправ'
      ].some((k) => action.includes(k) || details.includes(k));
