  // Print State
  const [printFiles, setPrintFiles] = useState<{id: string, name: string, type: string, url: string, printed_at?: string, supplier_id?: string}[]>([]);
  const [printSupplierId, setPrintSupplierId] = useState('');
  const [printBotDiagnostics, setPrintBotDiagnostics] = useState('');
  const [printBotDiagnosticsOpen, setPrintBotDiagnosticsOpen] = useState(false);
  const printFileInputRef = useRef<HTMLInputElement>(null);

  const handlePrintFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files);
      files.forEach(file => {
        const reader = new FileReader();
        reader.onload = (e) => {
          if (e.target?.result) {
            setPrintFiles(prev => [...prev, {
              id: Math.random().toString(36).substr(2, 9),
              name: file.name,
              type: file.type,
              url: e.target!.result as string,
              supplier_id: printSupplierId
            }]);
          }
        };
        reader.readAsDataURL(file);
      });
    }
    if (printFileInputRef.current) printFileInputRef.current.value = '';
  };

  const handlePrintFile = (id: string) => {
    setPrintFiles(prev => prev.map(f => f.id === id ? { ...f, printed_at: new Date().toLocaleString('ru-RU') } : f));

    const file = printFiles.find(f => f.id === id);
    if (file) {
      logAction('Печать файла', `Распечатан файл: ${file.name}`, currentEmployee?.id);
      if (file.type.includes('image')) {
        const win = window.open('', '_blank');
        if (win) {
          win.document.write(`
            <html>
              <head><title>Print</title></head>
              <body style="margin:0; display:flex; justify-content:center; align-items:center; min-height:100vh;">
                <img src="${file.url}" style="max-width:100%; max-height:100vh;" onload="setTimeout(() => { window.print(); }, 500)" />
              </body>
            </html>
          `);
          win.document.close();
        }
      } else {
        window.open(file.url, '_blank');
      }
    }
  };

  const handleDeletePrintFile = async (id: string) => {
    if (!window.confirm('Удалить файл?')) return;

    try {
        const file = printFiles.find(f => f.id === id);
        const { error } = await supabase.from('print_files').delete().eq('id', id);

        if (error) throw error;

        if (file) {
            await logAction('Удаление файла', `Удален файл: ${file.name}`, currentEmployee?.id);
        }

        setPrintFiles(prev => prev.filter(f => f.id !== id));
        showToast('Файл удален', 'success');
    } catch (e: any) {
        showToast('Ошибка удаления: ' + e.message, 'error');
    }
  };

  const getFileIcon = (type: string) => {
    if (type.includes('pdf')) return <FileText className="h-6 w-6 text-red-500" />;
    if (type.includes('sheet') || type.includes('excel')) return <FileSpreadsheet className="h-6 w-6 text-green-500" />;
    if (type.includes('image')) return <Camera className="h-6 w-6 text-blue-500" />;
    return <File className="h-6 w-6 text-gray-400" />;
  };

  const refreshDatabaseLogs = async () => {
    const { data } = await supabase.from('app_settings').select('*').eq('key', 'database_backup_logs').maybeSingle();
    if (data) {
        try {
            const parsed = typeof data.value === 'string' ? JSON.parse(data.value) : data.value;
            if (Array.isArray(parsed)) {
                setDatabaseLogs(parsed);
                showToast('История обновлена', 'success');
            }
        } catch (e) {
            console.error('Failed to parse database logs', e);
            showToast('Ошибка обновления истории', 'error');
        }
    } else {
        // If no logs found, maybe fetch all settings to be sure?
        // Or just do nothing
    }
  };

  const handleDownloadDatabase = async () => {
    const tables = ['suppliers', 'products', 'supplies', 'boxes', 'supply_items', 'employees'];
    const dbData: any = {};

    try {
      for (const table of tables) {
        const { data } = await supabase.from(table).select('*');
        dbData[table] = data || [];
      }

      const blob = new Blob([JSON.stringify(dbData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `database_backup_${new Date().toISOString().split('T')[0]}.json`;
      a.click();
      URL.revokeObjectURL(url);
      showToast('База данных успешно скачана', 'success');
    } catch (e: any) {
      showToast('Ошибка скачивания базы: ' + e.message, 'error');
    }
  };

  const fetchPrintFiles = async () => {
    if (!printSupplierId) {
      setPrintFiles([]);
      return;
    }

    const { data, error } = await supabase
      .from('print_files')
      .select('*')
      .eq('supplier_id', printSupplierId)
      .order('created_at', { ascending: false });

    if (error) {
      showToast('Ошибка загрузки файлов: ' + error.message, 'error');
    } else {
      setPrintFiles(data || []);
    }
  };

  useEffect(() => {
    fetchPrintFiles();
  }, [printSupplierId]);

  const runPrintBotDiagnostics = async () => {
    if (!printSupplierId) return showToast('Выберите поставщика', 'error');
    const supplier = suppliers.find(s => String(s.id) === String(printSupplierId));
    const chatId = String((supplier as any)?.telegram_chat_id || '').trim();
    if (!chatId) return showToast('У поставщика не заполнен Telegram Chat ID', 'error');

    const token = String((telegramBotTokenFile || telegramBotToken || '').trim());
    if (!token) return showToast('Не задан Telegram Bot Token', 'error');

    try {
      const updatesJson = await telegramService.getUpdates(token, 100);
      if (!updatesJson?.ok) throw new Error(updatesJson?.description || 'Telegram getUpdates error');

      const updates = (updatesJson.result || [])
        .map((u: any) => u?.message)
        .filter((m: any) => m && String(m?.chat?.id) === chatId)
        .sort((a: any, b: any) => (b?.date || 0) - (a?.date || 0))
        .slice(0, 20);

      const lines = updates.map((m: any, idx: number) => {
        const dt = m?.date ? new Date(m.date * 1000).toLocaleString('ru-RU') : '-';
        const text = String(m?.text || '').slice(0, 120);
        const doc = m?.document ? `doc:${m.document.file_name || m.document.file_id}` : '';
        const btn = m?.reply_markup?.keyboard ? 'keyboard' : (m?.reply_markup?.inline_keyboard ? 'inline_keyboard' : '');
        return `${idx + 1}) ${dt} | ${text || '-'} ${doc ? '| ' + doc : ''} ${btn ? '| ' + btn : ''}`;
      });

      const report = [
        `Поставщик: ${supplier?.name || '-'}`,
        `Chat ID: ${chatId}`,
        `Найдено сообщений: ${updates.length}`,
        '',
        ...lines,
      ].join('\n');

      setPrintBotDiagnostics(report);
      setPrintBotDiagnosticsOpen(true);
      showToast('Диагностика бота готова', 'success');
    } catch (e: any) {
      showToast('Ошибка диагностики бота: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const fetchReportMetric = async (metric: string, start?: string, end?: string) => {
    const { data: stats, error } = await supabase.rpc('get_supplier_stats', {
        p_start_date: start || null,
        p_end_date: end || null
    });

    if (error) {
        console.error(`Error fetching ${metric}:`, error);
        return;
    }

    if (metric === 'stock') {
        setReportStockData(stats.map((s: any) => ({ name: s.supplier_name, value: s.received - s.shipped })));
    } else if (metric === 'payment') {
        setReportPaymentData(stats.map((s: any) => ({ name: s.supplier_name, value: s.total_payment })));
    } else if (metric === 'boxes') {
        setReportBoxData(stats.map((s: any) => ({ name: s.supplier_name, value: s.boxes })));
    } else if (metric === 'packaging') {
        setReportPackagingData(stats.map((s: any) => ({ name: s.supplier_name, value: s.packaging_cost })));
    }
  };

  const fetchReportsData = async () => {
    setLoadingReports(true);
    try {
        // Prepare all promises
        const itemsCountPromise = supabase.from('supply_items').select('*', { count: 'exact', head: true }).is('deleted_at', null);
        const suppliesCountPromise = supabase.from('supplies').select('*', { count: 'exact', head: true }).is('deleted_at', null);
        const boxDataPromise = supabase.rpc('get_box_stats');
        const allStatsPromise = supabase.rpc('get_supplier_stats', {
            p_start_date: '2000-01-01',
            p_end_date: '2099-12-31'
        });
        const suppliersDataPromise = supabase.from('suppliers').select('id, name').is('deleted_at', null);

        // Prepare metrics promises
        const metrics = ['stock', 'payment', 'boxes', 'packaging'];
        const uniqueRanges = new Map<string, string[]>();

        metrics.forEach(metric => {
            const start = reportDates[metric]?.start ?? '';
            const end = reportDates[metric]?.end ?? '';
            const key = `${start}|${end}`;
            if (!uniqueRanges.has(key)) {
                uniqueRanges.set(key, []);
            }
            uniqueRanges.get(key)?.push(metric);
        });

        const metricsPromises = Array.from(uniqueRanges.entries()).map(async ([key, metricList]) => {
            const [rawStart, rawEnd] = key.split('|');
            const start = rawStart && rawStart !== 'undefined' ? rawStart : null;
            const end = rawEnd && rawEnd !== 'undefined' ? rawEnd : null;

            const { data: stats, error } = await supabase.rpc('get_supplier_stats', {
                p_start_date: start,
                p_end_date: end
            });

            if (error) {
                console.error(`Error fetching stats for ${key}:`, error);
                return null;
            }
            return { metricList, stats };
        });

        // Execute all promises in parallel
        const [
            { count: itemsCount },
            { count: suppliesCount },
            { data: boxData },
            { data: allStats },
            { data: suppliersData },
            metricsResults
        ] = await Promise.all([
            itemsCountPromise,
            suppliesCountPromise,
            boxDataPromise,
            allStatsPromise,
            suppliersDataPromise,
            Promise.all(metricsPromises)
        ]);

        // Process Box Stats
        let avgBoxPrice = 0;
        if (boxData && boxData.length > 0) {
            avgBoxPrice = boxData[0].avg_price || 0;
            setBoxStats({
                totalAdded: boxData[0].total_added || 0,
                totalUsed: boxData[0].total_used || 0,
                currentStock: boxData[0].current_stock || 0,
                avgPrice: boxData[0].avg_price || 0
            });
        }

        // Process Global Stats
        let totalPayments = 0;
        let totalPackaging = 0;
        let totalBoxesCount = 0;

        if (allStats) {
            totalPayments = allStats.reduce((sum: number, s: any) => sum + (s.total_payment || 0), 0);
            totalPackaging = allStats.reduce((sum: number, s: any) => sum + (s.packaging_cost || 0), 0);
            totalBoxesCount = allStats.reduce((sum: number, s: any) => sum + (s.boxes || 0), 0);
        }

        const totalBoxesCost = totalBoxesCount * avgBoxPrice;
        const totalCost = totalPayments + totalPackaging + totalBoxesCost;
        const avgPriceInStock = (itemsCount || 0) > 0 ? totalCost / (itemsCount || 0) : 0;

        setReportTotals({ items: itemsCount || 0, supplies: suppliesCount || 0, avgPriceInStock });

        // Process Metrics Results
        metricsResults.forEach((result: any) => {
            if (!result) return;
            const { metricList, stats } = result;
            metricList.forEach((metric: string) => {
                if (metric === 'stock') {
                    setReportStockData(stats.map((s: any) => ({ name: s.supplier_name, value: s.received - s.shipped })));
                } else if (metric === 'payment') {
                    setReportPaymentData(stats.map((s: any) => ({ name: s.supplier_name, value: s.total_payment })));
                } else if (metric === 'boxes') {
                    setReportBoxData(stats.map((s: any) => ({ name: s.supplier_name, value: s.boxes })));
                } else if (metric === 'packaging') {
                    setReportPackagingData(stats.map((s: any) => ({ name: s.supplier_name, value: s.packaging_cost })));
                }
            });
        });

        // Process Suppliers All Time Stats
        if (suppliersData) {
            const results = suppliersData.map((supplier: any) => {
                const supplierStats = allStats ? allStats.find((s: any) => s.supplier_id === supplier.id || s.supplier_name === supplier.name) : null;
                return {
                    id: supplier.id,
                    name: supplier.name,
                    stats: supplierStats || null,
                    avgBoxPrice: avgBoxPrice
                };
            });
            setSuppliersAllTimeStats(results);
        }

    } catch (e) {
        console.error('Error fetching reports:', e);
        showToast('Ошибка загрузки отчетов', 'error');
    } finally {
        setLoadingReports(false);
    }
  };



  const validateUploadedReportSupplier = async (rows: any[], supplierId: string) => {
    try {
      const reportCodes = new Set(
        (rows || [])
          .map((r: any) => String(r?.['Код номенклатуры'] ?? '').trim())
          .filter((x: string) => !!x)
      );
      if (!reportCodes.size) return true;

      const { data, error } = await supabase
        .from('products')
        .select('wb_sku, article, name')
        .eq('supplier_id', supplierId)
        .is('deleted_at', null)
        .limit(20000);
      if (error) throw error;

      const supplierCodes = new Set<string>();
      (data || []).forEach((p: any) => {
        const sku = String(p?.wb_sku ?? '').trim();
        const art = String(p?.article ?? '').trim();
        if (sku) supplierCodes.add(sku);
        if (art) supplierCodes.add(art);
      });

      if (!supplierCodes.size) return true;

      let overlap = 0;
      reportCodes.forEach((c) => { if (supplierCodes.has(c)) overlap += 1; });
      return overlap > 0;
    } catch (e) {
      console.error('validateUploadedReportSupplier error', e);
      return true;
    }
  };


  const loadUploadedCostsForSupplier = async (supplierId: string) => {
    if (!supplierId) {
      setUploadedPersistedCostByCode({});
      return;
    }
    try {
      const { data } = await supabase.from('app_settings').select('value').eq('key', 'analytics_costs_v1').maybeSingle();
      let parsed: any = {};
      const raw = data?.value;
      if (typeof raw === 'string') {
        try { parsed = JSON.parse(raw); } catch { parsed = {}; }
      } else if (raw && typeof raw === 'object') {
        parsed = raw;
      }
      const map = (parsed?.[supplierId] && typeof parsed[supplierId] === 'object') ? parsed[supplierId] : {};
      const normalized: Record<string, number> = {};
      Object.entries(map || {}).forEach(([k, v]) => {
        const num = Number(v as any);
        if (Number.isFinite(num)) normalized[String(k)] = num;
      });
      setUploadedPersistedCostByCode(normalized);

      if ((uploadedReportAnalytics || []).length > 0) {
        const seeded: Record<string, string> = {};
        (uploadedReportAnalytics || []).forEach((r: any) => {
          const code = String(r?.code || '').trim();
          const key = `${code}|${r?.name || ''}`;
          if (code && normalized[code] != null) seeded[key] = String(normalized[code]);
        });
        setUploadedCostByKey((prev) => ({ ...seeded, ...(prev || {}) }));
      }
    } catch (e) {
      console.error('loadUploadedCostsForSupplier error', e);
      setUploadedPersistedCostByCode({});
    }
  };

  const persistUploadedCostsByCode = async (nextByCode: Record<string, number>) => {
    const { data } = await supabase.from('app_settings').select('value').eq('key', 'analytics_costs_v1').maybeSingle();
    let parsed: any = {};
    const raw = data?.value;
    if (typeof raw === 'string') {
      try { parsed = JSON.parse(raw); } catch { parsed = {}; }
    } else if (raw && typeof raw === 'object') {
      parsed = raw;
    }
    const merged = { ...(parsed || {}), [uploadedSelectedSupplierId]: nextByCode };
    const payload = JSON.stringify(merged);

    const { data: updatedRows, error: updateError } = await supabase
      .from('app_settings')
      .update({ value: payload })
      .eq('key', 'analytics_costs_v1')
      .select('key');
    if (updateError) throw updateError;
    if (!updatedRows || updatedRows.length === 0) {
      const { error: insertError } = await supabase.from('app_settings').insert({ key: 'analytics_costs_v1', value: payload });
      if (insertError) throw insertError;
    }
  };

  const saveUploadedCosts = async () => {
    if (!uploadedSelectedSupplierId) {
      showToast('Сначала выберите поставщика', 'error');
      return;
    }
    try {
      setUploadedSavingCosts(true);
      const nextByCode: Record<string, number> = { ...(uploadedPersistedCostByCode || {}) };
      Object.entries(uploadedCostByKey || {}).forEach(([key, val]) => {
        const num = Number(String(val ?? '').replace(',', '.'));
        if (key && Number.isFinite(num) && String(val).trim() !== '') nextByCode[key] = num;
      });
      await persistUploadedCostsByCode(nextByCode);
      setUploadedPersistedCostByCode(nextByCode);
      showToast('Себестоимость сохранена', 'success');
    } catch (e: any) {
      console.error('saveUploadedCosts error', e);
      showToast('Не удалось сохранить себестоимость', 'error');
    } finally {
      setUploadedSavingCosts(false);
    }
  };


  const getUploadedCostKeyCandidates = (row: any) => {
    const code = String(row?.code || '').trim();
    const name = String(row?.name || '').trim();
    return Array.from(new Set([code, name ? `name:${name}` : '', code && name ? `${code}|${name}` : ''].filter(Boolean)));
  };

  const getUploadedCostValue = (row: any, persistedMap?: Record<string, number>, rowMap?: Record<string, string>) => {
    const keyMap = rowMap || uploadedCostByKey;
    for (const candidate of getUploadedCostKeyCandidates(row)) {
      const fromKey = keyMap[candidate];
      if (fromKey !== undefined && String(fromKey).trim() !== '') {
        const n = Number(String(fromKey).replace(',', '.'));
        if (Number.isFinite(n) && n > 0) return n;
      }
    }
    const persistedSource = persistedMap || uploadedPersistedCostByCode;
    for (const candidate of getUploadedCostKeyCandidates(row)) {
      const persisted = persistedSource[candidate];
      if (Number.isFinite(Number(persisted)) && Number(persisted) > 0) return Number(persisted);
    }

    const directCandidates = [
      row?.cost,
      row?.unit_cost,
      row?.unitCost,
      row?.cost_price,
      row?.costPrice,
      row?.purchase_cost,
      row?.purchaseCost,
      row?.prime_cost,
      row?.primeCost,
      row?.sebestoimost,
      row?.['Себестоимость'],
    ];
    for (const candidate of directCandidates) {
      if (candidate === undefined || candidate === null || String(candidate).trim() === '') continue;
      const n = Number(String(candidate).replace(/\s+/g, '').replace(',', '.'));
      if (Number.isFinite(n) && n > 0) return n;
    }

    return 0;
  };

  const uploadedCostEditorItems = useMemo(() => {
    const map = new Map<string, any>();
    (uploadedReportAnalytics || []).forEach((r: any) => {
      const code = String(r?.code || '').trim();
      if (!code) return;
      if (!map.has(code)) map.set(code, r);
    });
    const q = uploadedCostEditorSearch.trim().toLowerCase();
    let rows = Array.from(map.values())
      .filter((r: any) => {
        const editorKey = `${String(r?.code || '').trim()}|${String(r?.name || '').trim()}`;
        if (Array.isArray(uploadedCostEditorLockedKeys) && uploadedCostEditorLockedKeys.length > 0) {
          if (!uploadedCostEditorLockedKeys.includes(editorKey)) return false;
        } else {
          const hasPrice = getUploadedCostValue(r) > 0;
          if (uploadedCostEditorFilter === 'with_price' && !hasPrice) return false;
          if (uploadedCostEditorFilter === 'without_price' && hasPrice) return false;
        }
        if (!q) return true;
        return String(r?.code || '').toLowerCase().includes(q) || String(r?.name || '').toLowerCase().includes(q);
      })
      .sort((a: any, b: any) => String(a?.name || '').localeCompare(String(b?.name || ''), 'ru'));

    if (Array.isArray(uploadedCostEditorLockedKeys) && uploadedCostEditorLockedKeys.length > 0) {
      const order = new Map(uploadedCostEditorLockedKeys.map((k, idx) => [k, idx]));
      rows = rows.sort((a: any, b: any) => {
        const ak = `${String(a?.code || '').trim()}|${String(a?.name || '').trim()}`;
        const bk = `${String(b?.code || '').trim()}|${String(b?.name || '').trim()}`;
        return Number(order.get(ak) ?? 999999) - Number(order.get(bk) ?? 999999);
      });
    }
    return rows;
  }, [uploadedReportAnalytics, uploadedCostEditorSearch, uploadedCostEditorFilter, uploadedCostByKey, uploadedPersistedCostByCode]);

  const openUploadedCostEditor = () => {
    const init: Record<string, string> = {};
    (uploadedReportAnalytics || []).forEach((r: any) => {
      const v = getUploadedCostValue(r);
      if (v > 0) {
        const code = String(r?.code || '').trim();
        const name = String(r?.name || '').trim();
        if (code) init[`${code}|${name}`] = String(v);
      }
    });
    setUploadedCostEditorValues(init);
    setUploadedCostEditorSearch('');
    setUploadedCostEditorFilter('all');
    setUploadedCostEditorLockedKeys(null);
    setUploadedCostEditorOpen(true);
  };

  const saveUploadedCostsFromEditor = async () => {
    if (!uploadedSelectedSupplierId) {
      showToast('Сначала выберите поставщика', 'error');
      return;
    }
    try {
      setUploadedSavingCosts(true);
      const nextByCode: Record<string, number> = { ...(uploadedPersistedCostByCode || {}) };
      Object.entries(uploadedCostEditorValues || {}).forEach(([code, val]) => {
        const c = String(code || '').trim();
        const num = Number(String(val ?? '').replace(',', '.'));
        if (c && Number.isFinite(num) && String(val).trim() !== '') nextByCode[c] = num;
      });
      await persistUploadedCostsByCode(nextByCode);
      setUploadedPersistedCostByCode(nextByCode);
      const seeded: Record<string, string> = {};
      (uploadedReportAnalytics || []).forEach((r: any) => {
        const value = getUploadedCostValue(r, nextByCode);
        const code = String(r?.code || '').trim();
        const key = `${code}|${r?.name || ''}`;
        if (value > 0) seeded[key] = String(value);
      });
      setUploadedCostByKey(seeded);
      setUploadedCostEditorOpen(false);
      showToast('Себестоимость сохранена', 'success');
    } catch (e: any) {
      console.error('saveUploadedCostsFromEditor error', e);
      showToast('Не удалось сохранить себестоимость', 'error');
    } finally {
      setUploadedSavingCosts(false);
    }
  };

  const processUploadedWbReport = (rows: any[], opts?: { turbo?: boolean }) => {
    const turbo = Boolean(opts?.turbo);
    const toNum = (v: any) => {
      const n = Number(String(v ?? '').replace(/\s+/g, '').replace(',', '.'));
      return Number.isFinite(n) ? n : 0;
    };

    const salesKeys = ['Вайлдберриз реализовал Товар (Пр)', 'Продажи', 'Сумма розничной цены', 'Сумма продаж'];
    const logisticsKeys = ['Услуги по доставке товара покупателю', 'Логистика', 'Логистика (руб)', 'Стоимость логистики'];
    const payoutKeys = ['К перечислению Продавцу за реализованный Товар', 'К перечислению', 'К перечислению продавцу за товар'];
    const fineKeys = ['Общая сумма штрафов', 'Штрафы'];
    const storageKeys = ['Хранение', 'Хранение (руб)', 'Платное хранение'];
    const withholdKeys = ['Удержания', 'Прочие удержания', 'Дедукции'];

    const pickNum = (row: any, keys: string[]) => {
      for (const k of keys) {
        if (row?.[k] !== undefined && row?.[k] !== null && String(row?.[k]).trim() !== '') return toNum(row[k]);
      }
      return 0;
    };

    const parseAnyDate = (v: any): Date | null => {
      if (v == null || String(v).trim() === '') return null;
      if (v instanceof Date && !Number.isNaN(v.getTime())) return v;
      if (typeof v === 'number' && Number.isFinite(v)) {
        // Excel serial date support
        const excelEpoch = new Date(Date.UTC(1899, 11, 30));
        const dt = new Date(excelEpoch.getTime() + v * 24 * 60 * 60 * 1000);
        return Number.isNaN(dt.getTime()) ? null : dt;
      }
      const str = String(v).trim();

      // dd.mm.yyyy [h:mm[:ss]]
      const dmY = str.match(/^(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{4})(?:\s+(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?)?$/);
      if (dmY) {
        const [, d, m, y, hh = '0', mm = '0', ss = '0'] = dmY;
        const dt = new Date(Number(y), Number(m) - 1, Number(d), Number(hh), Number(mm), Number(ss));
        return Number.isNaN(dt.getTime()) ? null : dt;
      }

      // yyyy-mm-dd [h:mm[:ss]]
      const ymd = str.match(/^(\d{4})-(\d{1,2})-(\d{1,2})(?:\s+(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?)?$/);
      if (ymd) {
        const [, y, m, d, hh = '0', mm = '0', ss = '0'] = ymd;
        const dt = new Date(Number(y), Number(m) - 1, Number(d), Number(hh), Number(mm), Number(ss));
        return Number.isNaN(dt.getTime()) ? null : dt;
      }

      const iso = new Date(str);
      return Number.isNaN(iso.getTime()) ? null : iso;
    };

    const pickDate = (row: any, keys: string[]) => {
      for (const k of keys) {
        const dt = parseAnyDate(row?.[k]);
        if (dt) return dt;
      }
      return null;
    };

    const pickDateByNormalizedKey = (row: any, keyName: string) => {
      const target = String(keyName || '').toLowerCase().replace(/\s+/g, ' ').trim();
      for (const [rk, rv] of Object.entries(row || {})) {
        const norm = String(rk || '').toLowerCase().replace(/\s+/g, ' ').trim();
        if (norm === target || norm.includes(target)) {
          const dt = parseAnyDate(rv);
          if (dt) return dt;
        }
      }
      return null;
    };

    const normalizeKey = (k: string) => String(k || '').toLowerCase().replace(/\s+/g, ' ').trim();
    const compareSizesAsc = (aSize: string, bSize: string) => {
      const prep = (v: string) => String(v || '').trim().toUpperCase();
      const a = prep(aSize);
      const b = prep(bSize);
      const rank = (v: string) => {
        if (!v || v === 'БЕЗ РАЗМЕРА' || v === 'БЕЗ Р-РА' || v === 'NONE' || v === 'NO SIZE') return 100000;

        const fixed: Record<string, number> = {
          XXS: 10,
          XS: 20,
          S: 30,
          M: 40,
          L: 50,
          XL: 60,
          XXL: 70,
          XXXL: 80,
          XXXXL: 90,
        };
        if (fixed[v] != null) return fixed[v];

        const xL = v.match(/^X+L$/i);
        if (xL) return 50 + String(v).replace(/[^X]/gi, '').length * 10;

        const numXL = v.match(/^(\d+)\s*XL$/i);
        if (numXL) return 60 + Number(numXL[1]) * 10;

        const pureNum = Number(v);
        if (!Number.isNaN(pureNum) && v !== '') return 500 + pureNum;

        return 90000;
      };
      const ra = rank(a);
      const rb = rank(b);
      if (ra !== rb) return ra - rb;
      return a.localeCompare(b, 'ru', { numeric: true });
    };
    const pickNumByIncludes = (row: any, includes: string[]) => {
      const entries = Object.entries(row || {});
      for (const [rawKey, rawVal] of entries) {
        const nk = normalizeKey(rawKey);
        const ok = includes.every((part) => nk.includes(part));
        if (!ok) continue;
        if (rawVal === undefined || rawVal === null || String(rawVal).trim() === '') continue;
        return toNum(rawVal);
      }
      return 0;
    };

    const pickTextByIncludes = (row: any, includes: string[], excludes: string[] = []) => {
      const entries = Object.entries(row || {});
      for (const [rawKey, rawVal] of entries) {
        const nk = normalizeKey(rawKey);
        const ok = includes.every((part) => nk.includes(part));
        const bad = excludes.some((part) => nk.includes(part));
        if (!ok || bad) continue;
        if (rawVal === undefined || rawVal === null) continue;
        const txt = String(rawVal).trim();
        if (!txt) continue;
        return txt;
      }
      return '';
    };

    const grouped = new Map<string, any>();
    const daily = new Map<string, any>();
    let periodStart: Date | null = null;
    let periodEnd: Date | null = null;

    const reportNumberKeys = ['Номер отчета', 'Номер отчёта', '№ отчета', '№ отчёта', 'Номер документа', 'Отчет №', 'Отчёт №'];
    let reportNumber = '';
    for (const r of (rows || [])) {
      for (const k of reportNumberKeys) {
        const v = String(r?.[k] ?? '').trim();
        if (v) {
          reportNumber = v;
          break;
        }
      }
      if (reportNumber) break;
    }

    (rows || []).forEach((row: any) => {
      const code = String(row?.['Код номенклатуры'] ?? row?.['nmID'] ?? '').trim();
      const name = String(row?.['Название'] ?? row?.['Предмет'] ?? row?.['Артикул поставщика'] ?? row?.['Бренд'] ?? '').trim() || 'Без названия';
      const key = `${code}|${name}`;

      const docType = String(row?.['Тип документа'] ?? '').toLowerCase();
      const reason = String(row?.['Обоснование для оплаты'] ?? '').toLowerCase();
      const isReturnByText = docType.includes('возврат') || reason.includes('возврат');

      const sales = pickNum(row, salesKeys);
      const logistics = pickNum(row, logisticsKeys);
      const payout = pickNum(row, payoutKeys);
      const fine = pickNum(row, fineKeys);
      const storage = pickNum(row, storageKeys);
      const withhold = pickNum(row, withholdKeys);
      const qty = pickNum(row, ['Кол-во', 'Количество', 'Колво', 'Кол-во товаров', 'quantity']);
      const sizeColumnEntry = Object.entries(row || {}).find(([k]) => normalizeKey(String(k)) === 'размер');
      const sizeRaw = String(sizeColumnEntry ? sizeColumnEntry[1] : (row?.['Размер'] ?? '')).trim();
      const sizeValue = sizeRaw || 'Без размера';
      const acquiring = pickNum(row, ['Эквайринг/Комиссии за организацию платежей', 'Комиссии за организацию платежей', 'Эквайринг'])
        || pickNumByIncludes(row, ['комисс', 'организац', 'платеж'])
        || pickNumByIncludes(row, ['эквайр']);

      const acquiringPercent = pickNum(row, ['Размер комиссии за эквайринг/Комиссии за организацию платежей, %', 'Размер комиссии за эквайринг, %', 'Комиссия за организацию платежей, %'])
        || pickNumByIncludes(row, ['комисс', 'эквайр', '%'])
        || pickNumByIncludes(row, ['комисс', 'организац', 'платеж', '%']);

      const isReturn = isReturnByText || qty < 0 || sales < 0 || payout < 0;
      const isSale = !isReturn && (docType.includes('продажа') || qty > 0 || sales > 0 || payout > 0);

      const reasonIsService = [
        'логист',
        'хранен',
        'штраф',
        'удержан',
        'возмещен',
        'корректировк',
        'приемк',
        'эквайринг',
        'комисси',
      ].some((x) => reason.includes(x));

      // Qty for profit formula must be only real product ops, not service rows
      const isQtyEligibleSale = isSale && !reasonIsService;
      const isQtyEligibleReturn = isReturn && !reasonIsService;

      const hasCodeForPeriod = String(row?.['Код номенклатуры'] ?? '').trim() !== '';
      const isProductOperationForPeriod = hasCodeForPeriod && (isSale || isReturn);
      const opDate = pickDate(row, ['Дата продажи']) || pickDateByNormalizedKey(row, 'Дата продажи');
      const opTaxRate = opDate && !Number.isNaN(opDate.getTime()) ? getTaxRateByYear(opDate.getFullYear()) : 0;
      const signedSalesForTax = isReturn ? -Math.abs(sales) : (isSale ? Math.max(0, sales) : 0);
      const taxDelta = signedSalesForTax * opTaxRate;
      if (isProductOperationForPeriod && opDate) {
        if (!periodStart || opDate < periodStart) periodStart = opDate;
        if (!periodEnd || opDate > periodEnd) periodEnd = opDate;
      }

      const item = grouped.get(key) || {
        code,
        name,
        sales_gross: 0,
        returns_gross: 0,
        sales_net: 0,
        logistics_sum: 0,
        payout_sum: 0,
        payout_sales_sum: 0,
        payout_returns_sum: 0,
        fine_sum: 0,
        storage_sum: 0,
        withhold_sum: 0,
        sold_qty: 0,
        return_qty: 0,
        acquiring_sum: 0,
        tax_sum: 0,
        acquiring_percent_sum: 0,
        acquiring_percent_count: 0,
        size_stats: {},
      };

      if (isReturn) {
        item.returns_gross += Math.abs(sales);
        item.payout_returns_sum += Math.abs(payout);
      } else if (isSale) {
        item.sales_gross += sales;
        item.payout_sales_sum += payout;
      }

      item.logistics_sum += logistics;
      item.payout_sum += payout;
      item.fine_sum += fine;
      item.storage_sum += storage;
      item.withhold_sum += withhold;
      item.acquiring_sum += acquiring;
      item.tax_sum += taxDelta;
      if (acquiringPercent) {
        item.acquiring_percent_sum += acquiringPercent;
        item.acquiring_percent_count += 1;
      }

      if (isSale || isReturn) {
        if (!item.size_stats[sizeValue]) {
          item.size_stats[sizeValue] = {
            sold: 0,
            ret: 0,
            sales_gross: 0,
            returns_gross: 0,
            logistics_sum: 0,
            payout_sales_sum: 0,
            payout_returns_sum: 0,
            fine_sum: 0,
            storage_sum: 0,
            withhold_sum: 0,
            acquiring_sum: 0,
            tax_sum: 0,
            acquiring_percent_sum: 0,
            acquiring_percent_count: 0,
          };
        }

        const sizeStat = item.size_stats[sizeValue];
        sizeStat.logistics_sum += logistics;
        sizeStat.fine_sum += fine;
        sizeStat.storage_sum += storage;
        sizeStat.withhold_sum += withhold;
        sizeStat.acquiring_sum += acquiring;
        sizeStat.tax_sum += taxDelta;
        if (acquiringPercent) {
          sizeStat.acquiring_percent_sum += acquiringPercent;
          sizeStat.acquiring_percent_count += 1;
        }

        if (isSale) {
          if (isQtyEligibleSale) {
            const saleQty = Math.abs(qty);
            const finalSaleQty = saleQty > 0 ? saleQty : 1;
            item.sold_qty += finalSaleQty;
            sizeStat.sold += finalSaleQty;
          }
          sizeStat.sales_gross += sales;
          sizeStat.payout_sales_sum += payout;
        } else if (isReturn) {
          if (isQtyEligibleReturn) {
            const retQty = Math.abs(qty);
            const finalRetQty = retQty > 0 ? retQty : 1;
            item.return_qty += finalRetQty;
            sizeStat.ret += finalRetQty;
          }
          sizeStat.returns_gross += Math.abs(sales);
          sizeStat.payout_returns_sum += Math.abs(payout);
        }
      }

      const hasDateForDaily = opDate && !Number.isNaN(opDate.getTime());
      if (hasDateForDaily) {
        const d = opDate as Date;
        const dKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
        const dk = `${key}|${dKey}`;
        const cur = daily.get(dk) || {
          code,
          name,
          date: dKey,
          sales_net: 0,
          returns_gross: 0,
          logistics_sum: 0,
          payout_net: 0,
          fine_sum: 0,
          storage_sum: 0,
          withhold_sum: 0,
          to_pay_total: 0,
          sold_qty: 0,
          return_qty: 0,
          acquiring_sum: 0,
        };

        cur.logistics_sum += logistics;
        cur.fine_sum += fine;
        cur.storage_sum += storage;
        cur.withhold_sum += withhold;
        cur.acquiring_sum += acquiring;

        if (isSale) {
          cur.sales_net += Math.max(0, sales);
          cur.payout_net += Math.max(0, payout);
          if (isQtyEligibleSale) cur.sold_qty += Math.abs(qty) > 0 ? Math.abs(qty) : 1;
        } else if (isReturn) {
          cur.returns_gross += Math.abs(sales);
          cur.payout_net -= Math.abs(payout);
          if (isQtyEligibleReturn) cur.return_qty += Math.abs(qty) > 0 ? Math.abs(qty) : 1;
        }

        cur.to_pay_total = Number(cur.payout_net || 0) - Number(cur.logistics_sum || 0) - Number(cur.storage_sum || 0) - Number(cur.fine_sum || 0) - Number(cur.withhold_sum || 0);
        daily.set(dk, cur);
      }

      grouped.set(key, item);
    });

    const analytics = [...grouped.values()].map((x) => {
      const salesNet = x.sales_gross - x.returns_gross;
      const soldNetQty = Math.max(0, Number(x.sold_qty || 0) - Number(x.return_qty || 0));
      const payoutNet = Number(x.payout_sales_sum || 0) - Number(x.payout_returns_sum || 0);
      const toPayTotal = payoutNet - Number(x.logistics_sum || 0) - Number(x.storage_sum || 0) - Number(x.fine_sum || 0) - Number(x.withhold_sum || 0);
      const sizeBreakdown = Object.entries(x.size_stats || {})
        .map(([size, st]: any) => {
          const sold = Number((st as any)?.sold || 0);
          const ret = Number((st as any)?.ret || 0);
          const net = sold - ret;
          const salesGross = Number((st as any)?.sales_gross || 0);
          const returnsGross = Number((st as any)?.returns_gross || 0);
          const salesNetBySize = salesGross - returnsGross;
          const payoutNetBySize = Number((st as any)?.payout_sales_sum || 0) - Number((st as any)?.payout_returns_sum || 0);
          const logisticsBySize = Number((st as any)?.logistics_sum || 0);
          const fineBySize = Number((st as any)?.fine_sum || 0);
          const storageBySize = Number((st as any)?.storage_sum || 0);
          const withholdBySize = Number((st as any)?.withhold_sum || 0);
          const acquiringBySize = Number((st as any)?.acquiring_sum || 0);
          const taxBySize = Number((st as any)?.tax_sum || 0);
          const toPayBySize = payoutNetBySize - logisticsBySize - fineBySize - storageBySize - withholdBySize;
          const acquiringPercentBySize = salesNetBySize > 0 ? (acquiringBySize / salesNetBySize) * 100 : 0;
          return {
            size: String(size),
            sold,
            ret,
            net,
            sales_net: salesNetBySize,
            returns_gross: returnsGross,
            logistics_sum: logisticsBySize,
            payout_net: payoutNetBySize,
            fine_sum: fineBySize,
            storage_sum: storageBySize,
            withhold_sum: withholdBySize,
            to_pay_total: toPayBySize,
            sold_qty: sold,
            sold_net_qty: Math.max(0, net),
            return_qty: ret,
            acquiring_sum: acquiringBySize,
            tax_sum: taxBySize,
            acquiring_percent: acquiringPercentBySize,
          };
        })
        .filter((z: any) => {
          const allZero =
            Number(z?.sales_net || 0) === 0 &&
            Number(z?.returns_gross || 0) === 0 &&
            Number(z?.logistics_sum || 0) === 0 &&
            Number(z?.payout_net || 0) === 0 &&
            Number(z?.fine_sum || 0) === 0 &&
            Number(z?.storage_sum || 0) === 0 &&
            Number(z?.withhold_sum || 0) === 0 &&
            Number(z?.to_pay_total || 0) === 0 &&
            Number(z?.sold_net_qty || 0) === 0 &&
            Number(z?.return_qty || 0) === 0 &&
            Number(z?.acquiring_sum || 0) === 0;
          return !allZero;
        })
        .sort((a: any, b: any) => compareSizesAsc(String(a?.size || ''), String(b?.size || '')));

      return {
        ...x,
        sales_net: salesNet,
        sold_net_qty: soldNetQty,
        payout_net: payoutNet,
        to_pay_total: toPayTotal,
        size_breakdown: sizeBreakdown.map((z: any) => `${z.size}: ${z.net}`).join(' • '),
        size_breakdown_list: sizeBreakdown,
        acquiring_percent: salesNet > 0 ? (Number(x.acquiring_sum || 0) / salesNet) * 100 : 0,
      };
    }).sort((a, b) => Number(b.sales_net || 0) - Number(a.sales_net || 0));

    const summary = {
      report_number: reportNumber || null,
      period_start: periodStart ? periodStart.toISOString() : null,
      period_end: periodEnd ? periodEnd.toISOString() : null,
      items: analytics.length,
      sales_net: analytics.reduce((s, x) => s + Number(x.sales_net || 0), 0),
      returns_gross: analytics.reduce((s, x) => s + Number(x.returns_gross || 0), 0),
      logistics_sum: analytics.reduce((s, x) => s + Number(x.logistics_sum || 0), 0),
      payout_sum: analytics.reduce((s, x) => s + Number(x.payout_sum || 0), 0),
      payout_net: analytics.reduce((s, x) => s + Number(x.payout_net || 0), 0),
      fine_sum: analytics.reduce((s, x) => s + Number(x.fine_sum || 0), 0),
      storage_sum: analytics.reduce((s, x) => s + Number(x.storage_sum || 0), 0),
      withhold_sum: analytics.reduce((s, x) => s + Number(x.withhold_sum || 0), 0),
      to_pay_total: analytics.reduce((s, x) => s + Number(x.to_pay_total || 0), 0),
      sold_qty: analytics.reduce((s, x) => s + Number(x.sold_qty || 0), 0),
      return_qty: analytics.reduce((s, x) => s + Number(x.return_qty || 0), 0),
      acquiring_sum: analytics.reduce((s, x) => s + Number(x.acquiring_sum || 0), 0),
      acquiring_percent: (analytics.reduce((s, x) => s + Number(x.acquiring_sum || 0), 0) > 0 && analytics.reduce((s, x) => s + Number(x.sales_net || 0), 0) > 0)
        ? (analytics.reduce((s, x) => s + Number(x.acquiring_sum || 0), 0) / analytics.reduce((s, x) => s + Number(x.sales_net || 0), 0)) * 100
        : 0,
      tax_sum: analytics.reduce((s, x) => s + Number(x.tax_sum || 0), 0),
      profit_total: analytics.reduce((s, x) => {
        const sold = Number(x.sold_qty || 0);
        const cost = Number(uploadedPersistedCostByCode[String(x.code || '').trim()] || 0);
        const avg = sold > 0 ? (Number(x.to_pay_total || 0) / sold) - cost : 0;
        const baseProfit = avg * sold;
        const taxValue = Number(x.tax_sum || 0);
        return s + (baseProfit - taxValue);
      }, 0),
    };

    const dailySeriesMap: Record<string, { code: string; name: string; points: any[] }> = {};
    if (!turbo) {
      Array.from(daily.values()).forEach((d: any) => {
        const k = `${String(d?.code || '')}|${String(d?.name || '')}`;
        if (!dailySeriesMap[k]) dailySeriesMap[k] = { code: String(d?.code || ''), name: String(d?.name || ''), points: [] };
        dailySeriesMap[k].points.push(d);
      });
      Object.values(dailySeriesMap).forEach((v: any) => v.points.sort((a: any, b: any) => String(a?.date || '').localeCompare(String(b?.date || ''))));
    }

    setUploadedDailySeries(dailySeriesMap);
    if (!uploadedChartKey && !turbo) {
      const firstK = Object.keys(dailySeriesMap)[0] || '';
      if (firstK) setUploadedChartKey(firstK);
    }

    setUploadedReportAnalytics(analytics);
    setUploadedReportSummary(summary);
    const seededCosts: Record<string, string> = {};
    const missingCostValues: Record<string, string> = {};
    let missingCount = 0;

    analytics.forEach((r: any) => {
      const code = String(r?.code || '').trim();
      const key = `${code}|${r?.name || ''}`;
      const resolvedCost = getUploadedCostValue(r);
      if (code && Number.isFinite(Number(resolvedCost)) && Number(resolvedCost) > 0) {
        seededCosts[key] = String(resolvedCost);
      } else if (code) {
        missingCostValues[key] = '';
        missingCount += 1;
      }
    });

    setUploadedCostByKey(seededCosts);

    if (missingCount > 0 && !turbo) {
      setUploadedCostEditorValues((prev) => ({ ...prev, ...missingCostValues }));
      setUploadedCostEditorSearch('');
      setUploadedCostEditorOpen(true);
      showToast(`Найдено новых товаров без себестоимости: ${missingCount}. Заполните себестоимость.`, 'warning');
    } else if (turbo) {
      showToast(`Турбо-режим: аналитика построена (${analytics.length} номенклатур), графики и авто-окно себестоимости отключены для скорости`, 'info');
    } else {
      showToast(`Аналитика построена: ${analytics.length} номенклатур`, 'success');
    }
    return { analytics, summary };
  };



  const ensureAnalyticsSuppliers = async () => {
    if (Array.isArray(suppliers) && suppliers.length > 0) return;
    try {
      const { data, error } = await supabase
        .from('suppliers')
        .select('id, name, telegram_chat_id, wb_api_token, created_at, deleted_at')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      if (Array.isArray(data) && data.length > 0) {
        setSuppliers(data as any);
      }
    } catch (e) {
      console.error('ensureAnalyticsSuppliers error', e);
    }
  };

  const loadAnalyticsSupplierOptions = async () => {
    try {
      const fromState = (suppliers || [])
        .filter((x: any) => String(x?.name || '').trim())
        .map((x: any) => ({ id: String(x.id), name: String(x.name) }));
      if (fromState.length > 0) {
        setUploadedAnalyticsSuppliers(fromState);
        return;
      }

      // direct fetch (light columns)
      const { data, error } = await supabase
        .from('suppliers')
        .select('id, name')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (!error && Array.isArray(data) && data.length > 0) {
        setUploadedAnalyticsSuppliers(data.map((x: any) => ({ id: String(x.id), name: String(x.name || '') })).filter((x: any) => x.name));
        return;
      }

      // fallback from history if suppliers endpoint temporarily unavailable
      const { data: hist } = await supabase
        .from('analytics_upload_history')
        .select('supplier_id, supplier_name')
        .order('created_at', { ascending: false })
        .limit(200);
      const uniq = new Map<string, string>();
      (hist || []).forEach((h: any) => {
        const id = String(h?.supplier_id || '').trim();
        const name = String(h?.supplier_name || '').trim();
        if (id && name && !uniq.has(id)) uniq.set(id, name);
      });
      const arr = Array.from(uniq.entries()).map(([id, name]) => ({ id, name }));
      if (arr.length > 0) setUploadedAnalyticsSuppliers(arr);
    } catch (e) {
      console.error('loadAnalyticsSupplierOptions error', e);
    }
  };

    const loadUploadedRawReportHistory = async (supplierId: string) => {
    if (!supplierId) {
      setUploadedRawReports([]);
      return;
    }
    try {
      const { data, error } = await supabase
        .from('analytics_upload_reports_raw')
        .select('id, supplier_id, supplier_name, file_name, period_start, period_end, summary_json, created_at')
        .eq('supplier_id', supplierId)
        .order('period_start', { ascending: true, nullsFirst: false })
        .order('created_at', { ascending: true })
        .limit(300);
      if (error) throw error;
      setUploadedRawReports(Array.isArray(data) ? data : []);
    } catch (e) {
      console.error('loadUploadedRawReportHistory error', e);
      setUploadedRawReports([]);
    }
  };

  const saveUploadedRawReportHistory = async (rows: any[], fileName?: string, summaryArg?: any, sourceFile?: File) => {
    if (!uploadedSelectedSupplierId || !Array.isArray(rows) || !rows.length) return;
    try {
      const supplier = (suppliers || []).find((s: any) => String(s?.id) === String(uploadedSelectedSupplierId));
      const summary = summaryArg || null;
      const reportNumber = String(summary?.report_number || '').trim();
      const ps = summary?.period_start ? new Date(summary.period_start).toLocaleDateString('ru-RU') : '-';
      const pe = summary?.period_end ? new Date(summary.period_end).toLocaleDateString('ru-RU') : '-';
      const supplierName = supplier?.name || 'Без поставщика';
      const defaultName = `Период Продаж_${ps}_${pe}_${supplierName}`;

      let sourceFileBucket: string | null = null;
      let sourceFilePath: string | null = null;
      let sourceFileSize: number | null = null;
      if (sourceFile && uploadedSelectedSupplierId) {
        try {
          const safeName = String(fileName || sourceFile.name || 'raw_report.xlsx').replace(/[^a-zA-Z0-9._-]+/g, '_');
          const now = new Date();
          const yyyy = String(now.getFullYear());
          const mm = String(now.getMonth() + 1).padStart(2, '0');
          const dd = String(now.getDate()).padStart(2, '0');
          const targetPath = `${uploadedSelectedSupplierId}/${yyyy}/${mm}/${dd}/${Date.now()}_${safeName}`;
          const { error: uploadErr } = await supabase.storage.from(RAW_REPORTS_BUCKET).upload(targetPath, sourceFile, {
            cacheControl: '3600',
            upsert: false,
            contentType: sourceFile.type || 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
          });
          if (!uploadErr) {
            sourceFileBucket = RAW_REPORTS_BUCKET;
            sourceFilePath = targetPath;
            sourceFileSize = Number(sourceFile.size || 0);
          } else {
            console.error('raw source upload error', uploadErr);
            showToast('Исходный файл не загружен в Storage, сохранены данные отчёта', 'warning');
          }
        } catch (storageErr) {
          console.error('raw source upload exception', storageErr);
          showToast('Ошибка Storage: исходный файл не загружен, сохранены данные отчёта', 'warning');
        }
      }

      // Hotfix: never persist full raw rows in DB to avoid memory pressure/crashes
      const shouldStoreRawRows = false;
      showToast(`RAW строки (${rows.length.toLocaleString('ru-RU')}) не сохраняются в БД: сохраняется только сводка`, 'info');

      const payload: any = {
        supplier_id: uploadedSelectedSupplierId,
        supplier_name: supplierName,
        file_name: defaultName,
        period_start: summary?.period_start ? new Date(summary.period_start).toISOString().slice(0, 10) : null,
        period_end: summary?.period_end ? new Date(summary.period_end).toISOString().slice(0, 10) : null,
        report_number: reportNumber || null,
        summary_json: { ...(summary || {}), source_file_name: fileName || null, source_file_bucket: sourceFileBucket, source_file_path: sourceFilePath, source_file_size: sourceFileSize, original_rows_count: Array.isArray(rows) ? rows.length : 0, rows_json_truncated: !shouldStoreRawRows },
        rows_json: shouldStoreRawRows ? rows : [],
      };

      const saveWithPayload = async (p: any) => {
        if (reportNumber) {
          const { data: existing, error: findErr } = await supabase
            .from('analytics_upload_reports_raw')
            .select('id')
            .eq('supplier_id', uploadedSelectedSupplierId)
            .eq('report_number', reportNumber)
            .maybeSingle();
          if (findErr) throw findErr;

          if (existing?.id) {
            const { error } = await supabase
              .from('analytics_upload_reports_raw')
              .update(p)
              .eq('id', existing.id);
            if (error) throw error;
          } else {
            const { error } = await supabase.from('analytics_upload_reports_raw').insert(p);
            if (error) throw error;
          }
        } else {
          const { error } = await supabase.from('analytics_upload_reports_raw').insert(p);
          if (error) throw error;
        }
      };

      const saveWithRetry = async (p: any, attempts = 3) => {
        let lastErr: any = null;
        for (let i = 1; i <= attempts; i += 1) {
          try {
            await saveWithPayload(p);
            return;
          } catch (err: any) {
            lastErr = err;
            const msg = String(err?.message || err || '').toLowerCase();
            const retryable = msg.includes('failed to fetch') || msg.includes('timeout') || msg.includes('network') || msg.includes('gateway');
            if (!retryable || i >= attempts) break;
            await new Promise((r) => setTimeout(r, 500 * i));
          }
        }
        throw lastErr;
      };

      try {
        await saveWithRetry(payload, 3);
      } catch (firstErr: any) {
        console.error('saveUploadedRawReportHistory full payload error', firstErr);

        // fallback for older table schema and/or oversized payload: keep rows + summary without binary file
        const fallbackPayload: any = {
          supplier_id: uploadedSelectedSupplierId,
          supplier_name: supplierName,
          file_name: defaultName,
          summary_json: { ...(summary || {}), source_file_name: fileName || null, source_file_bucket: sourceFileBucket, source_file_path: sourceFilePath, source_file_size: sourceFileSize },
          rows_json: shouldStoreRawRows ? rows : [],
        };

        try {
          await saveWithRetry(fallbackPayload, 2);
          showToast('Отчёт сохранён в облегченном формате', 'info');
        } catch (secondErr: any) {
          console.error('saveUploadedRawReportHistory fallback error', secondErr);
          throw secondErr;
        }
      }

      await loadUploadedRawReportHistory(uploadedSelectedSupplierId);
    } catch (e: any) {
      console.error('saveUploadedRawReportHistory error', e);
      showToast(`Не удалось сохранить WB отчёт в БД: ${e?.message || 'ошибка'}`, 'error');
    }
  };

  const fetchRawRowsByIds = async (ids: string[]) => {
    const cleanIds = Array.from(new Set((ids || []).map((x) => String(x || '').trim()).filter(Boolean)));
    if (!cleanIds.length) return [] as any[];
    const { data, error } = await supabase
      .from('analytics_upload_reports_raw')
      .select('id, rows_json')
      .in('id', cleanIds as any)
      .limit(Math.max(1, cleanIds.length));
    if (error) throw error;
    const byId = new Map<string, any[]>();
    (data || []).forEach((r: any) => {
      byId.set(String(r?.id || ''), Array.isArray(r?.rows_json) ? r.rows_json : []);
    });
    return cleanIds.flatMap((id) => byId.get(id) || []);
  };

  const openUploadedRawHistoryItem = async (item: any) => {
    try {
      let rows = Array.isArray(item?.rows_json) ? item.rows_json : [];
      if (!rows.length && item?.id) {
        rows = await fetchRawRowsByIds([String(item.id)]);
      }
      if (!rows.length) {
        showToast('В сохранённом WB отчёте нет строк', 'error');
        return;
      }
      processUploadedWbReport(rows);
      setUploadedRawHistoryPickerOpen(false);
      showToast('WB отчёт открыт из отдельной истории', 'success');
    } catch (e) {
      console.error('openUploadedRawHistoryItem error', e);
      showToast('Не удалось открыть WB отчёт из истории', 'error');
    }
  };

  const openUploadedRawHistoryMonth = async (items: any[]) => {
    try {
      let rows = (Array.isArray(items) ? items : []).flatMap((x: any) => (Array.isArray(x?.rows_json) ? x.rows_json : []));
      if (!rows.length) {
        const ids = (Array.isArray(items) ? items : []).map((x: any) => String(x?.id || '')).filter(Boolean);
        rows = await fetchRawRowsByIds(ids);
      }
      if (!rows.length) {
        showToast('Нет данных WB отчётов за выбранный месяц', 'error');
        return;
      }
      processUploadedWbReport(rows);
      setUploadedRawHistoryPickerOpen(false);
      showToast('Открыт объединённый WB отчёт за месяц', 'success');
    } catch (e) {
      console.error('openUploadedRawHistoryMonth error', e);
      showToast('Не удалось открыть отчёт за месяц', 'error');
    }
  };


  const downloadUploadedRawSourceFile = async (item: any) => {
    const b64 = String(item?.summary_json?.source_file_base64 || '').trim();
    const srcName = String(item?.summary_json?.source_file_name || item?.file_name || 'source_report.xlsx');
    const sourceBucket = String(item?.summary_json?.source_file_bucket || '').trim();
    const sourcePath = String(item?.summary_json?.source_file_path || '').trim();

    try {
      if (sourceBucket && sourcePath) {
        const { data, error } = await supabase.storage.from(sourceBucket).download(sourcePath);
        if (!error && data) {
          const url = URL.createObjectURL(data);
          const a = document.createElement('a');
          a.href = url;
          a.download = srcName.endsWith('.xlsx') || srcName.endsWith('.xls') ? srcName : `${srcName}.xlsx`;
          document.body.appendChild(a);
          a.click();
          a.remove();
          URL.revokeObjectURL(url);
          return;
        }
      }

      if (b64) {
        const bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
        const blob = new Blob([bytes], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = srcName.endsWith('.xlsx') || srcName.endsWith('.xls') ? srcName : `${srcName}.xlsx`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        URL.revokeObjectURL(url);
        return;
      }

      const rows = Array.isArray(item?.rows_json) ? item.rows_json : [];
      if (!rows.length) {
        showToast('Для этой записи нет исходных строк отчёта', 'error');
        return;
      }

      await downloadJsonRowsAsExcel(rows, srcName, 'WB Report Raw');
      showToast('Файл восстановлен из данных БД и скачан', 'success');
    } catch (e) {
      console.error('downloadUploadedRawSourceFile error', e);
      showToast('Не удалось скачать исходный файл', 'error');
    }
  };

  const deleteUploadedRawHistoryItem = async (id: string, fileName?: string) => {
    if (!id) return;
    const label = String(fileName || 'этот WB отчёт');
    const ok = window.confirm(`Удалить из истории WB: ${label}?`);
    if (!ok) return;
    try {
      const { error } = await supabase.from('analytics_upload_reports_raw').delete().eq('id', id);
      if (error) throw error;
      await loadUploadedRawReportHistory(uploadedSelectedSupplierId);
      showToast('WB отчёт удалён из отдельной истории', 'success');
    } catch (e) {
      console.error('deleteUploadedRawHistoryItem error', e);
      showToast('Не удалось удалить WB отчёт', 'error');
    }
  };

  const loadUploadedReportHistory = async (supplierId: string) => {
    if (!supplierId) return;
    try {
      setUploadedHistoryLoading(true);
      const { data, error } = await supabase
        .from('analytics_upload_history')
        .select('id, supplier_id, supplier_name, file_name, summary_json, created_at')
        .eq('supplier_id', supplierId)
        .order('created_at', { ascending: false })
        .limit(200);
      if (error) throw error;
      const sorted = (Array.isArray(data) ? data : []).sort((a: any, b: any) => {
        const da = new Date(a?.summary_json?.period_start || a?.created_at || 0).getTime();
        const db = new Date(b?.summary_json?.period_start || b?.created_at || 0).getTime();
        return da - db;
      });
      setUploadedHistory(sorted);
    } catch (e) {
      console.error('loadUploadedReportHistory error', e);
      setUploadedHistory([]);
    } finally {
      setUploadedHistoryLoading(false);
    }
  };

  const recalcAnalyticsToPayWithoutAcquiring = (arr: any[]) => {
    return (Array.isArray(arr) ? arr : []).map((x: any) => {
      const payoutFallback = Number(x?.payout_sales_sum || 0) - Number(x?.payout_returns_sum || 0);
      const payoutNet = Number(x?.payout_net ?? payoutFallback);
      const logistics = Number(x?.logistics_sum || 0);
      const storage = Number(x?.storage_sum || 0);
      const fine = Number(x?.fine_sum || 0);
      const withhold = Number(x?.withhold_sum || 0);
      const toPay = payoutNet - logistics - storage - fine - withhold;
      return { ...x, payout_net: payoutNet, to_pay_total: toPay };
    });
  };

  const fetchUploadedHistoryDetailsByIds = async (ids: string[]) => {
    const cleanIds = Array.from(new Set((ids || []).map((x) => String(x || '').trim()).filter(Boolean)));
    if (!cleanIds.length) return [] as any[];
    const { data, error } = await supabase
      .from('analytics_upload_history')
      .select('id, summary_json, analytics_json')
      .in('id', cleanIds as any)
      .limit(Math.max(1, cleanIds.length));
    if (error) throw error;
    return Array.isArray(data) ? data : [];
  };

  const openUploadedHistoryItem = async (item: any) => {
    try {
      let analytics = Array.isArray(item?.analytics_json) ? item.analytics_json : [];
      let summary = item?.summary_json || null;
      if ((!analytics.length || !summary) && item?.id) {
        const rows = await fetchUploadedHistoryDetailsByIds([String(item.id)]);
        const found = (rows || [])[0] || null;
        if (found) {
          analytics = Array.isArray(found?.analytics_json) ? found.analytics_json : analytics;
          summary = found?.summary_json || summary;
        }
      }
      if (!Array.isArray(analytics) || analytics.length === 0) {
        showToast('В этом отчёте нет сохранённых данных аналитики', 'error');
        return;
      }

      const recalcedAnalytics = recalcAnalyticsToPayWithoutAcquiring(analytics);

      const dateCandidates = recalcedAnalytics
        .map((x: any) => new Date(x?.operation_date || x?.date || x?.created_at || ''))
        .filter((d: Date) => !Number.isNaN(d.getTime()))
        .sort((a: Date, b: Date) => a.getTime() - b.getTime());

      const summaryTaxRate = getUploadedTaxRate(summary);
      const normalizedSummary = summary ? {
        ...summary,
        return_qty: recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.return_qty || 0), 0),
        acquiring_sum: recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.acquiring_sum || 0), 0),
        acquiring_percent: (recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.sales_net || 0), 0) > 0)
          ? (recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.acquiring_sum || 0), 0) / recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.sales_net || 0), 0)) * 100
          : 0,
        profit_total: recalcedAnalytics.reduce((acc: number, x: any) => {
          const sold = Number(x?.sold_qty || 0);
          const cost = Number(uploadedPersistedCostByCode[String(x?.code || '').trim()] || 0);
          const avg = sold > 0 ? (Number(x?.to_pay_total || 0) / sold) - cost : 0;
          const baseProfit = avg * sold;
          const taxValue = Number(x?.sales_net || 0) * summaryTaxRate;
          return acc + (baseProfit - taxValue);
        }, 0),
        period_start: summary?.period_start || (dateCandidates[0] ? dateCandidates[0].toISOString() : null),
        period_end: summary?.period_end || (dateCandidates.length ? dateCandidates[dateCandidates.length - 1].toISOString() : null),
      } : summary;

      setUploadedReportAnalytics(recalcedAnalytics);
      setUploadedReportSummary(normalizedSummary);
      setUploadedDailySeries({});
      setUploadedChartKey('');
      setUploadedViewTab('table');

      if (item?.id) {
        try {
          await supabase
            .from('analytics_upload_history')
            .update({ analytics_json: recalcedAnalytics, summary_json: normalizedSummary })
            .eq('id', item.id);
        } catch {}
      }

      showToast('Отчёт открыт из истории', 'success');
    } catch (e) {
      console.error('openUploadedHistoryItem error', e);
      showToast('Не удалось открыть отчёт из истории', 'error');
    }
  };


  const openUploadedHistoryMonth = async (items: any[]) => {
    const rows = Array.isArray(items) ? items : [];
    if (!rows.length) return;

    const grouped = new Map<string, any>();
    let periodStart: Date | null = null;
    let periodEnd: Date | null = null;

    const byId = new Map<string, any>();
    try {
      const ids = rows.map((r: any) => String(r?.id || '')).filter(Boolean);
      const details = await fetchUploadedHistoryDetailsByIds(ids);
      (details || []).forEach((d: any) => byId.set(String(d?.id || ''), d));
    } catch (e) {
      console.error('openUploadedHistoryMonth details fetch error', e);
    }

    rows.forEach((it: any) => {
      const detail = byId.get(String(it?.id || '')) || it;
      const arr = Array.isArray(detail?.analytics_json) ? detail.analytics_json : [];
      const summaryForDates = detail?.summary_json || it?.summary_json || {};
      const s0 = summaryForDates?.period_start ? new Date(summaryForDates.period_start) : null;
      const e0 = summaryForDates?.period_end ? new Date(summaryForDates.period_end) : null;
      if (s0 && !Number.isNaN(s0.getTime())) periodStart = !periodStart || s0 < periodStart ? s0 : periodStart;
      if (e0 && !Number.isNaN(e0.getTime())) periodEnd = !periodEnd || e0 > periodEnd ? e0 : periodEnd;

      const sourceYear = new Date(summaryForDates?.period_start || summaryForDates?.period_end || summaryForDates?.created_at || '').getFullYear();
      const sourceTaxRate = getTaxRateByYear(sourceYear);

      arr.forEach((r: any) => {
        const code = String(r?.code || '').trim();
        const name = String(r?.name || 'Без названия').trim();
        const key = `${code}|${name}`;
        const cur = grouped.get(key) || {
          code,
          name,
          sales_net: 0,
          returns_gross: 0,
          logistics_sum: 0,
          payout_sum: 0,
          payout_net: 0,
          fine_sum: 0,
          storage_sum: 0,
          withhold_sum: 0,
          to_pay_total: 0,
          sold_net_qty: 0,
          sold_qty: 0,
          return_qty: 0,
          acquiring_sum: 0,
          tax_sum: 0,
          acquiring_percent_sum: 0,
          acquiring_percent_count: 0,
          size_stats: {},
        };

        cur.sales_net += Number(r?.sales_net || 0);
        cur.returns_gross += Number(r?.returns_gross || 0);
        cur.logistics_sum += Number(r?.logistics_sum || 0);
        cur.payout_sum += Number(r?.payout_sum || 0);
        cur.payout_net += Number(r?.payout_net || 0);
        cur.fine_sum += Number(r?.fine_sum || 0);
        cur.storage_sum += Number(r?.storage_sum || 0);
        cur.withhold_sum += Number(r?.withhold_sum || 0);
        cur.to_pay_total += (Number(r?.payout_net || 0) - Number(r?.logistics_sum || 0) - Number(r?.storage_sum || 0) - Number(r?.fine_sum || 0) - Number(r?.withhold_sum || 0));
        cur.sold_net_qty += Number(r?.sold_net_qty || 0);
        cur.sold_qty += Number(r?.sold_qty || r?.sold_net_qty || 0);
        cur.return_qty += Number(r?.return_qty || 0);
        cur.acquiring_sum += Number(r?.acquiring_sum || 0);
        cur.tax_sum += Number(r?.tax_sum ?? (Number(r?.sales_net || 0) * sourceTaxRate));

        const ap = Number(r?.acquiring_percent || 0);
        if (ap > 0) {
          cur.acquiring_percent_sum += ap;
          cur.acquiring_percent_count += 1;
        }

        const sizeArr = Array.isArray(r?.size_breakdown_list) ? r.size_breakdown_list : [];
        sizeArr.forEach((sz: any) => {
          const sizeKey = String(sz?.size || 'Без размера');
          const prev = cur.size_stats[sizeKey] || {
            size: sizeKey,
            sales_net: 0,
            returns_gross: 0,
            logistics_sum: 0,
            payout_net: 0,
            fine_sum: 0,
            storage_sum: 0,
            withhold_sum: 0,
            to_pay_total: 0,
            sold_net_qty: 0,
            sold_qty: 0,
            return_qty: 0,
            acquiring_sum: 0,
            tax_sum: 0,
            acquiring_percent_sum: 0,
            acquiring_percent_count: 0,
          };
          prev.sales_net += Number(sz?.sales_net || 0);
          prev.returns_gross += Number(sz?.returns_gross || 0);
          prev.logistics_sum += Number(sz?.logistics_sum || 0);
          prev.payout_net += Number(sz?.payout_net || 0);
          prev.fine_sum += Number(sz?.fine_sum || 0);
          prev.storage_sum += Number(sz?.storage_sum || 0);
          prev.withhold_sum += Number(sz?.withhold_sum || 0);
          prev.to_pay_total += (Number(sz?.payout_net || 0) - Number(sz?.logistics_sum || 0) - Number(sz?.storage_sum || 0) - Number(sz?.fine_sum || 0) - Number(sz?.withhold_sum || 0));
          prev.sold_net_qty += Number(sz?.sold_net_qty || 0);
          prev.sold_qty += Number(sz?.sold_qty || sz?.sold_net_qty || 0);
          prev.return_qty += Number(sz?.return_qty || 0);
          prev.acquiring_sum += Number(sz?.acquiring_sum || 0);
          prev.tax_sum += Number(sz?.tax_sum || 0);
          const apSz = Number(sz?.acquiring_percent || 0);
          if (apSz > 0) {
            prev.acquiring_percent_sum += apSz;
            prev.acquiring_percent_count += 1;
          }
          cur.size_stats[sizeKey] = prev;
        });

        grouped.set(key, cur);
      });
    });

    const compareSizesAscLocal = (aSize: string, bSize: string) => {
      const prep = (v: string) => String(v || '').trim().toUpperCase();
      const a = prep(aSize);
      const b = prep(bSize);
      const rank = (v: string) => {
        if (!v || v === 'БЕЗ РАЗМЕРА' || v === 'БЕЗ Р-РА' || v === 'NONE' || v === 'NO SIZE') return 100000;

        const fixed: Record<string, number> = {
          XXS: 10,
          XS: 20,
          S: 30,
          M: 40,
          L: 50,
          XL: 60,
          XXL: 70,
          XXXL: 80,
          XXXXL: 90,
        };
        if (fixed[v] != null) return fixed[v];

        const xL = v.match(/^X+L$/i);
        if (xL) return 50 + String(v).replace(/[^X]/gi, '').length * 10;

        const numXL = v.match(/^(\d+)\s*XL$/i);
        if (numXL) return 60 + Number(numXL[1]) * 10;

        const pureNum = Number(v);
        if (!Number.isNaN(pureNum) && v !== '') return 500 + pureNum;

        return 90000;
      };
      const ra = rank(a);
      const rb = rank(b);
      if (ra !== rb) return ra - rb;
      return a.localeCompare(b, 'ru', { numeric: true });
    };

    const analytics = Array.from(grouped.values()).map((x: any) => {
      const sizeBreakdown = Object.values(x?.size_stats || {})
        .map((sz: any) => ({
          ...sz,
          acquiring_percent: Number(sz?.sales_net || 0) > 0 ? (Number(sz?.acquiring_sum || 0) / Number(sz?.sales_net || 0)) * 100 : 0,
        }))
        .sort((a: any, b: any) => compareSizesAscLocal(String(a?.size || ''), String(b?.size || '')));
      return {
        ...x,
        acquiring_percent: Number(x.sales_net || 0) > 0 ? (Number(x.acquiring_sum || 0) / Number(x.sales_net || 0)) * 100 : 0,
        size_breakdown: sizeBreakdown.map((z: any) => `${z.size}: ${Number(z.sold_net_qty || 0) - Number(z.return_qty || 0)}`).join(' • '),
        size_breakdown_list: sizeBreakdown,
      };
    }).sort((a: any, b: any) => Number(b.sales_net || 0) - Number(a.sales_net || 0));

    const summary = {
      report_number: null,
      period_start: periodStart ? periodStart.toISOString() : null,
      period_end: periodEnd ? periodEnd.toISOString() : null,
      items: analytics.length,
      sales_net: analytics.reduce((acc: number, x: any) => acc + Number(x.sales_net || 0), 0),
      returns_gross: analytics.reduce((acc: number, x: any) => acc + Number(x.returns_gross || 0), 0),
      logistics_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.logistics_sum || 0), 0),
      payout_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.payout_sum || 0), 0),
      payout_net: analytics.reduce((acc: number, x: any) => acc + Number(x.payout_net || 0), 0),
      fine_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.fine_sum || 0), 0),
      storage_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.storage_sum || 0), 0),
      withhold_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.withhold_sum || 0), 0),
      to_pay_total: analytics.reduce((acc: number, x: any) => acc + Number(x.to_pay_total || 0), 0),
      sold_qty: analytics.reduce((acc: number, x: any) => acc + Number(x.sold_qty || 0), 0),
      return_qty: analytics.reduce((acc: number, x: any) => acc + Number(x.return_qty || 0), 0),
      acquiring_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.acquiring_sum || 0), 0),
      acquiring_percent: (analytics.reduce((acc: number, x: any) => acc + Number(x.sales_net || 0), 0) > 0)
        ? (analytics.reduce((acc: number, x: any) => acc + Number(x.acquiring_sum || 0), 0) / analytics.reduce((acc: number, x: any) => acc + Number(x.sales_net || 0), 0)) * 100
        : 0,
      tax_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.tax_sum || 0), 0),
      profit_total: analytics.reduce((acc: number, x: any) => {
        const sold = Number(x.sold_qty || 0);
        const cost = Number(uploadedPersistedCostByCode[String(x.code || '').trim()] || 0);
        const avg = sold > 0 ? (Number(x.to_pay_total || 0) / sold) - cost : 0;
        const baseProfit = avg * sold;
        const taxValue = Number(x.tax_sum || 0);
        return acc + (baseProfit - taxValue);
      }, 0),
    };

    setUploadedReportAnalytics(analytics);
    setUploadedReportSummary(summary);
    setUploadedDailySeries({});
    setUploadedChartKey('');
    setUploadedViewTab('table');
    showToast('Открыт объединённый отчёт за месяц', 'success');
  };


