        rows,
        headers: ['Код номенклатуры', 'Название', 'Размеры', 'Продажи', 'Возвраты', 'Логистика', 'К перечислению', 'Штрафы', 'Хранение', 'Удержания', 'Итого к оплате (WB)', 'Себестоимость', 'Средний заработок с ед.', 'Заработок', 'Кол-во проданных', 'Кол-во возвратов', 'Эквайринг/Комиссии за организацию платежей', 'Размер комиссии за эквайринг/Комиссии за организацию платежей, %'],
