  useEffect(() => {
    if (!uploadedHistoryYears.length) return;
    if (uploadedHistoryYear == null || !uploadedHistoryYears.includes(uploadedHistoryYear)) {
      setUploadedHistoryYear(uploadedHistoryYears[uploadedHistoryYears.length - 1]);
    }
  }, [uploadedHistoryYears, uploadedHistoryYear]);

  const uploadedRawHistoryYears = useMemo(() => {
    const years = new Set<number>();
    (uploadedRawReports || []).forEach((h: any) => {
      const base = h?.period_start || h?.period_end || h?.summary_json?.period_start || h?.summary_json?.period_end || h?.created_at;
      const d = new Date(base || '');
      if (!Number.isNaN(d.getTime())) years.add(d.getFullYear());
    });
    return Array.from(years).sort((a, b) => a - b);
  }, [uploadedRawReports]);

  useEffect(() => {
    if (!uploadedRawHistoryYears.length) return;
    if (uploadedRawHistoryYear == null || !uploadedRawHistoryYears.includes(uploadedRawHistoryYear)) {
      setUploadedRawHistoryYear(uploadedRawHistoryYears[uploadedRawHistoryYears.length - 1]);
    }
  }, [uploadedRawHistoryYears, uploadedRawHistoryYear]);

  const uploadedRawHistoryGrouped = useMemo(() => {
    const byMonth = new Map<number, any[]>();
    (uploadedRawReports || []).forEach((h: any) => {
      const base = h?.period_start || h?.period_end || h?.summary_json?.period_start || h?.summary_json?.period_end || h?.created_at;
      const d = new Date(base || '');
      if (Number.isNaN(d.getTime())) return;
      if (uploadedRawHistoryYear != null && d.getFullYear() !== uploadedRawHistoryYear) return;
      const m = d.getMonth();
      if (!byMonth.has(m)) byMonth.set(m, []);
      byMonth.get(m)!.push(h);
    });
    const groups = Array.from(byMonth.entries()).sort((a, b) => a[0] - b[0]);
    groups.forEach(([, items]) => {
      items.sort((x: any, y: any) => {
        const dx = new Date(x?.period_start || x?.summary_json?.period_start || x?.created_at || 0).getTime();
        const dy = new Date(y?.period_start || y?.summary_json?.period_start || y?.created_at || 0).getTime();
        return dx - dy;
      });
    });
    return groups;
  }, [uploadedRawReports, uploadedRawHistoryYear]);

