                              <div><span className="text-gray-500">Доставка:</span><div>{log.type === 'FBS' ? `${getFbsDeliveryAmount(log).toFixed(2)} ₽` : (log.delivery_price ? `${log.delivery_price} ₽` : '-')}</div></div>
